                    placeholderTextColor={highContrast ? '#666' : colors.textSecondary}
                    multiline
                    numberOfLines={4}
                  />
                </View>
              </View>

              <View style={styles.modalActions}>
                <TouchableOpacity 
                  style={[styles.modalButton, styles.cancelButton]}
